import React, { useState, useEffect } from 'react';
import { Search, Filter, MapPin } from 'lucide-react';

const Home = ({ isLoggedIn, userRole }) => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [zona, setZona] = useState('Todas las zonas');

  const zonasTucuman = ['Todas las zonas', 'Barrio Norte', 'Barrio Sur', 'Yerba Buena', 'Tafí Viejo'];

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];
    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        zona: local.zona || 'Centro'
      }))];
    });
    setTodasLasOfertas(acumulador);
  }, []);

  return (
    <div style={{ background: '#f8fafc' }}>
      {/* SECCIÓN HERO: Aquí vuelve la imagen y el texto bello */}
      <div style={heroSection}>
        <div style={overlay}>
          <h1 style={heroTitle}>Las mejores ofertas <br/> <span style={{color: '#f97316'}}>cerca de ti</span></h1>
          <p style={heroSubtitle}>Ahorrá en tus compras diarias con los locales de tu barrio.</p>
          
          {/* BUSCADOR (Solo si no es vendedor) */}
          {userRole !== 'vendedor' && (
            <div style={searchContainer}>
              <Search size={20} color="#94a3b8" />
              <input 
                type="text" 
                placeholder="¿Qué buscás hoy?" 
                style={heroInput}
                onChange={(e) => setBusqueda(e.target.value)}
              />
              <button style={heroBtn}>Buscar</button>
            </div>
          )}
        </div>
      </div>

      {/* FILTROS DE ZONAS */}
      <div style={filterBar}>
        <div style={zonaScroll}>
          {zonasTucuman.map(z => (
            <button key={z} onClick={() => setZona(z)} style={zona === z ? zonaActive : zonaBtn}>
              {z}
            </button>
          ))}
        </div>
      </div>

      {/* GRILLA DE PRODUCTOS */}
      <div style={{ padding: '40px 8%' }}>
        <h2 style={sectionTitle}>Ofertas destacadas</h2>
        <div style={gridStyle}>
          {ofertasFiltradas.length > 0 ? (
            ofertasFiltradas.map(o => (
              <div key={o.id} style={cardStyle}>
                <div style={imgBox}>
                  {o.imagen ? <img src={o.imagen} style={imgStyle} alt={o.producto} /> : <MapPin size={40} color="#cbd5e1"/>}
                </div>
                <div style={{padding: '15px'}}>
                  <span style={localLabel}>{o.nombreLocal}</span>
                  <h3 style={productTitle}>{o.producto}</h3>
                  <div style={priceTag}>${o.precioNuevo}</div>
                </div>
              </div>
            ))
          ) : (
            <p style={{gridColumn: '1/-1', textAlign: 'center', color: '#64748b'}}>Todavía no hay ofertas cargadas en esta zona.</p>
          )}
        </div>
      </div>
    </div>
  );
};

// --- ESTILOS DE BELLEZA ---
const heroSection = {
  height: '500px',
  backgroundImage: 'url("https://images.unsplash.com/photo-1542838132-92c53300491e?ixlib=rb-1.2.1&auto=format&fit=crop&w=1350&q=80")', // Aquí va tu imagen bella
  backgroundSize: 'cover',
  backgroundPosition: 'center',
  position: 'relative'
};

const overlay = {
  position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
  backgroundColor: 'rgba(0,0,0,0.5)',
  display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center',
  textAlign: 'center', padding: '0 20px'
};

const heroTitle = { color: 'white', fontSize: '3.5rem', fontWeight: '800', marginBottom: '10px', lineHeight: '1.1' };
const heroSubtitle = { color: '#e2e8f0', fontSize: '1.2rem', marginBottom: '30px' };

const searchContainer = {
  display: 'flex', alignItems: 'center', background: 'white', 
  padding: '10px 20px', borderRadius: '50px', width: '100%', maxWidth: '600px',
  boxShadow: '0 10px 25px rgba(0,0,0,0.2)'
};

const heroInput = { border: 'none', outline: 'none', flex: 1, padding: '10px', fontSize: '1rem' };
const heroBtn = { background: '#f97316', color: 'white', border: 'none', padding: '10px 25px', borderRadius: '30px', fontWeight: 'bold', cursor: 'pointer' };

const filterBar = { padding: '20px 8%', background: 'white', borderBottom: '1px solid #e2e8f0' };
const zonaScroll = { display: 'flex', gap: '15px', overflowX: 'auto', scrollbarWidth: 'none' };
const zonaBtn = { padding: '10px 20px', borderRadius: '30px', border: '1px solid #cbd5e1', background: 'white', cursor: 'pointer', whiteSpace: 'nowrap' };
const zonaActive = { ...zonaBtn, background: '#1e293b', color: 'white', borderColor: '#1e293b' };

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '30px' };
const cardStyle = { background: 'white', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', transition: '0.3s' };
const imgBox = { height: '200px', background: '#f1f5f9', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const sectionTitle = { fontSize: '1.8rem', marginBottom: '25px', color: '#1e293b' };
const localLabel = { fontSize: '0.75rem', color: '#f97316', fontWeight: 'bold', textTransform: 'uppercase' };
const productTitle = { margin: '5px 0', fontSize: '1.2rem', color: '#1e293b' };
const priceTag = { fontSize: '1.5rem', fontWeight: '900', color: '#1e293b' };

export default Home;
